            let lo_str = &piece[..dash_idx];
            let hi_str = &piece[dash_idx + 1..];
            if lo_str.is_empty() && hi_str.is_empty() {
                return Err(piece.to_string());
            }
            let lo: usize = if lo_str.is_empty() {
                1
            } else {
                lo_str.parse().map_err(|_| piece.to_string())?
            };
