            } else {
                Some(hi_str.parse().map_err(|_| piece.to_string())?)
            };
            if lo == 0 {
                return Err(format!("__ZERO__:{}", lo));
            }
            match hi {
                Some(h) => {
                    if h == 0 {
                        return Err(format!("__ZERO__:{}", h));
