        if choice == 'single':
            parts.append(str(random.randint(1, max_idx)))
        elif choice == 'range':
            a = random.randint(1, max_idx)
            b = random.randint(a, max_idx+2)
            parts.append(f"{a}-{b}")
        elif choice == 'open_lo':
            parts.append(f"-{random.randint(1, max_idx)}")
        else:
            parts.append(f"{random.randint(1, max_idx)}-")
    return ','.join(parts)

def random_probe():
    args = []
    stdin = random_data()
