/// Process escapes like \t, \n in user-provided strings.
fn process_escapes(s: &str) -> Vec<u8> {
    // Looking at observed behavior: -D "\t" → tab. But the default is literal "\t" (tab char).
    // The CLI default for `-D` is the actual tab character. When the user writes `-D '\t'` from shell, bash already gives us literal `\t` chars.
    // hck doesn't seem to process escape sequences (since they come through bash); but if the default
    // shows "\t" as `\t` literally, then check.
    // For safety, just return raw bytes.
    s.as_bytes().to_vec()
}

