fn selection_would_emit(
    field_specs: Option<&[FieldSpec]>,
    exclude_specs: Option<&[FieldSpec]>,
) -> bool {
    let default_specs = vec![FieldSpec { start: 1, end: usize::MAX, is_open_end: true }];
    let f: &[FieldSpec] = match field_specs {
        Some(v) => v,
        None => &default_specs,
    };
    let e: &[FieldSpec] = exclude_specs.unwrap_or(&[]);

    // Determine max finite position to check.
    let mut max_finite = 1usize;
    for s in f.iter().chain(e.iter()) {
        max_finite = max_finite.max(s.start);
        if s.end != usize::MAX {
            max_finite = max_finite.max(s.end);
        }
    }
    let bound = max_finite + 2;

    let in_any = |specs: &[FieldSpec], p: usize| -> bool {
        specs.iter().any(|s| p >= s.start && (s.end == usize::MAX || p <= s.end))
    };

    for p in 1..=bound {
        let inf = in_any(f, p);
        let ine = in_any(e, p);
        if inf && !ine {
            return true;
        }
    }

    // Beyond bound: open tails.
    let any_open_field = f.iter().any(|s| s.end == usize::MAX);
    let any_open_exclude = e.iter().any(|s| s.end == usize::MAX);
    if any_open_field && !any_open_exclude {
        return true;
    }
    // If any open exclude exists, positions beyond bound are excluded.
    false
}

